interface Lead {
  id: string;
  studentName: string;
  parentPhone: string;
  parentName?: string;
  score?: number;
  interestedDirection: 'gaokao' | 'study_abroad' | 'military' | 'other';
  additionalInfo?: string;
  status: 'pending' | 'contacted' | 'planning' | 'completed' | 'invalid';
  createdAt: string;
}

const FIRESTORE_COLLECTION = process.env.FIRESTORE_LEADS_COLLECTION || "leads";
const LEADS_STORAGE = process.env.LEADS_STORAGE || (process.env.GOOGLE_APPLICATION_CREDENTIALS_JSON || process.env.GOOGLE_APPLICATION_CREDENTIALS_BASE64 ? "firestore" : "file");

let firestoreClient: Firestore | null = null;

function getServiceAccountCredentials() {
  const rawJson = process.env.GOOGLE_APPLICATION_CREDENTIALS_JSON;
  const rawBase64 = process.env.GOOGLE_APPLICATION_CREDENTIALS_BASE64;
  const rawCredentials = rawJson || (rawBase64 ? Buffer.from(rawBase64, "base64").toString("utf-8") : "");

  if (!rawCredentials) return null;

  const credentials = JSON.parse(rawCredentials);
  if (credentials.private_key) {
    credentials.private_key = credentials.private_key.replace(/\\n/g, "\n");
  }
  return credentials;
}

function getFirestoreClient() {
  if (!firestoreClient) {
    const credentials = getServiceAccountCredentials();
    const options: Record<string, unknown> = {};

    if (process.env.GOOGLE_CLOUD_PROJECT) {
      options.projectId = process.env.GOOGLE_CLOUD_PROJECT;
    }

    if (credentials) {
      options.projectId = process.env.GOOGLE_CLOUD_PROJECT || credentials.project_id;
      options.credentials = credentials;
    }

    firestoreClient = new Firestore(options);
  }

  return firestoreClient;
}

function ensureLocalLeadsFile() {
  if (!fs.existsSync(DATA_DIR)) {
    fs.mkdirSync(DATA_DIR, { recursive: true });
  }

  if (!fs.existsSync(LEADS_FILE)) {
    fs.writeFileSync(LEADS_FILE, JSON.stringify([], null, 2), "utf-8");
  }
}

async function readLeads(): Promise<Lead[]> {
  try {
    if (LEADS_STORAGE === "firestore") {
      const snapshot = await getFirestoreClient()
        .collection(FIRESTORE_COLLECTION)
        .orderBy("createdAt", "desc")
        .get();

      return snapshot.docs.map((doc) => ({ id: doc.id, ...doc.data() } as Lead));
    }

    ensureLocalLeadsFile();
    const data = fs.readFileSync(LEADS_FILE, "utf-8");
    return JSON.parse(data);
  } catch (error) {
    console.error("Error reading leads:", error);
    return [];
  }
}

async function createLead(lead: Lead): Promise<Lead> {
  if (LEADS_STORAGE === "firestore") {
    await getFirestoreClient().collection(FIRESTORE_COLLECTION).doc(lead.id).set(lead);
    return lead;
  }

  const leads = await readLeads();
  leads.unshift(lead);
  writeLocalLeads(leads);
  return lead;
}

async function updateLeadStatus(id: string, status: Lead["status"]): Promise<Lead | null> {
  if (LEADS_STORAGE === "firestore") {
    const docRef = getFirestoreClient().collection(FIRESTORE_COLLECTION).doc(id);
    const snapshot = await docRef.get();
    if (!snapshot.exists) return null;

    await docRef.update({ status });
    return { id: snapshot.id, ...snapshot.data(), status } as Lead;
  }

  const leads = await readLeads();
  const leadIndex = leads.findIndex((lead) => lead.id === id);
  if (leadIndex === -1) return null;

  leads[leadIndex].status = status;
  writeLocalLeads(leads);
  return leads[leadIndex];
}

async function deleteLead(id: string): Promise<boolean> {
  if (LEADS_STORAGE === "firestore") {
    const docRef = getFirestoreClient().collection(FIRESTORE_COLLECTION).doc(id);
    const snapshot = await docRef.get();
    if (!snapshot.exists) return false;

    await docRef.delete();
    return true;
  }

  const leads = await readLeads();
  const nextLeads = leads.filter((lead) => lead.id !== id);
  if (nextLeads.length === leads.length) return false;

  writeLocalLeads(nextLeads);
  return true;
}

function writeLocalLeads(leads: Lead[]) {
  try {
    ensureLocalLeadsFile();
    fs.writeFileSync(LEADS_FILE, JSON.stringify(leads, null, 2), "utf-8");
  } catch (error) {
    console.error("Error writing leads:", error);
  }
}

const ADMIN_COOKIE_NAME = "dfph_admin_session";
const ADMIN_SESSION_MAX_AGE_SECONDS = 60 * 60 * 8;
const ADMIN_PASSWORD = process.env.ADMIN_PASSWORD;
const ADMIN_SESSION_SECRET = process.env.ADMIN_SESSION_SECRET || ADMIN_PASSWORD || "local-development-secret";

function parseCookies(cookieHeader = "") {
  return cookieHeader
    .split(";")
    .map((part) => part.trim())
    .filter(Boolean)
    .reduce<Record<string, string>>((cookies, part) => {
      const separatorIndex = part.indexOf("=");
      if (separatorIndex === -1) return cookies;

      const name = part.slice(0, separatorIndex);
      const value = part.slice(separatorIndex + 1);
      cookies[name] = decodeURIComponent(value);
      return cookies;
    }, {});
}

function signAdminToken(expiresAt: number) {
  const payload = String(expiresAt);
  const signature = crypto
    .createHmac("sha256", ADMIN_SESSION_SECRET)
    .update(payload)
    .digest("base64url");

  return `${payload}.${signature}`;
}

function verifyAdminToken(token?: string) {
  if (!token) return false;

  const [payload, signature] = token.split(".");
  const expiresAt = Number(payload);
  if (!payload || !signature || !Number.isFinite(expiresAt) || expiresAt < Date.now()) {
    return false;
  }

  const expectedToken = signAdminToken(expiresAt);
  const expectedSignature = expectedToken.split(".")[1];
  const signatureBuffer = Buffer.from(signature);
  const expectedBuffer = Buffer.from(expectedSignature);

  return signatureBuffer.length === expectedBuffer.length && crypto.timingSafeEqual(signatureBuffer, expectedBuffer);
}

function setAdminCookie(res: Response) {
  const expiresAt = Date.now() + ADMIN_SESSION_MAX_AGE_SECONDS * 1000;
  const token = signAdminToken(expiresAt);
  const secureFlag = process.env.COOKIE_SECURE === "false"
    ? ""
    : process.env.NODE_ENV === "production"
      ? "; Secure"
      : "";

  res.setHeader(
    "Set-Cookie",
    `${ADMIN_COOKIE_NAME}=${encodeURIComponent(token)}; HttpOnly; Path=/; SameSite=Lax; Max-Age=${ADMIN_SESSION_MAX_AGE_SECONDS}${secureFlag}`
  );
}

function clearAdminCookie(res: Response) {
  res.setHeader(
    "Set-Cookie",
    `${ADMIN_COOKIE_NAME}=; HttpOnly; Path=/; SameSite=Lax; Max-Age=0`
  );
}

function requireAdmin(req: Request, res: Response, next: NextFunction) {
  const cookies = parseCookies(req.headers.cookie);

  if (!verifyAdminToken(cookies[ADMIN_COOKIE_NAME])) {
    return res.status(401).json({ error: "请先登录后台管理面板。" });
  }

  next();
}

