app.post("/api/admin/login", (req, res) => {
  if (!ADMIN_PASSWORD) {
    return res.status(500).json({ error: "后台管理口令尚未配置，请先设置 ADMIN_PASSWORD 环境变量。" });
  }

  const { password } = req.body;
  if (!password || password !== ADMIN_PASSWORD) {
    return res.status(401).json({ error: "后台管理口令错误。" });
  }

  setAdminCookie(res);
  res.json({ success: true });
});

app.post("/api/admin/logout", (_req, res) => {
  clearAdminCookie(res);
  res.json({ success: true });
});

app.get("/api/admin/session", (req, res) => {
  const cookies = parseCookies(req.headers.cookie);
  res.json({ authenticated: verifyAdminToken(cookies[ADMIN_COOKIE_NAME]) });
});

// 1. Submit a lead (public formulation form)
app.post("/api/leads", async (req, res) => {
  const { studentName, parentPhone, parentName, score, interestedDirection, additionalInfo } = req.body;

  if (!studentName || !parentPhone || !interestedDirection) {
    return res.status(400).json({ error: "学生姓名、联系方式和意向方向为必填项。" });
  }

  const newLead: Lead = {
    id: `lead_${Date.now()}`,
    studentName,
    parentPhone,
    parentName: parentName || "",
    score: score ? Number(score) : undefined,
    interestedDirection,
    additionalInfo: additionalInfo || "",
    status: "pending",
    createdAt: new Date().toISOString()
  };

  try {
    const lead = await createLead(newLead);
    res.status(201).json({ success: true, lead });
  } catch (error) {
    console.error("Error creating lead:", error);
    res.status(500).json({ error: "提交失败，请稍后再试或直接拨打招生专线。" });
  }
});

// 2. Fetch leads list for internal Counselor Dashboard
app.get("/api/leads", requireAdmin, async (_req, res) => {
  const leads = await readLeads();
  res.json({ leads });
});

// 3. Update status of lead
app.put("/api/leads/:id", requireAdmin, async (req, res) => {
  const { id } = req.params;
  const { status } = req.body;

  if (!status) {
    return res.status(400).json({ error: "状态值必填。" });
  }

  if (!["pending", "contacted", "planning", "completed", "invalid"].includes(status)) {
    return res.status(400).json({ error: "无效的状态值。" });
  }

  const lead = await updateLeadStatus(id, status);

  if (!lead) {
    return res.status(404).json({ error: "未找到该咨询记录。" });
  }

  res.json({ success: true, lead });
});

// 4. Delete a lead
app.delete("/api/leads/:id", requireAdmin, async (req, res) => {
  const { id } = req.params;
  const deleted = await deleteLead(id);

  if (!deleted) {
    return res.status(404).json({ error: "未找到该咨询记录。" });
  }

  res.json({ success: true });
});

